import numpy as np

def kmeans_weight_sharing(W: np.ndarray, k: int, n_iter: int = 100) -> tuple:
    flat = W.ravel().astype(np.float64)
    n = len(flat)
    # Initialize centroids
    init_idx = np.random.choice(n, k, replace=False)
    centroids = flat[init_idx].copy()

    indices = np.zeros(n, dtype=np.int32)
    for _ in range(n_iter):
        # Assign step
        dists = np.abs(flat[:, np.newaxis] - centroids[np.newaxis, :])
        indices = np.argmin(dists, axis=1).astype(np.int32)
        # Update step
        for c in range(k):
            mask = indices == c
            if np.any(mask):
                centroids[c] = flat[mask].mean()

    quantized_W = centroids[indices].reshape(W.shape)
    return quantized_W, centroids, indices.reshape(W.shape)

def weight_sharing_bits(k: int) -> int:
    import math
    return max(1, math.ceil(math.log2(k)))
